using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsFolder = Path.Combine(Directory.GetCurrentDirectory(), "uploads");

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            var filePath = Path.Combine(_uploadsFolder, filename);

            if (!Path.IsPathRooted(filePath) && !filePath.StartsWith(_uploadsFolder))
            {
                return NotFound();
            }

            if (System.IO.File.Exists(filePath))
            {
                var mimeType = MimeMapping.GetMimeMapping(filename);
                return File(System.IO.File.ReadAllBytes(filePath), mimeType);
            }
            else
            {
                return NotFound();
            }
        }
    }
